+    pending: 0,
+    removed: 0,
+    counter_pending: 0,
+    restored: 0,
+    dismissed: 0,
+  };
+
+  for (const request of store.requests.values()) {
+    stats[request.status] += 1;
+  }
+
+  return stats;
+}
